package com.example.sociallogin

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.os.Bundle
import androidx.activity.result.ActivityResultLauncher
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class SocialLoginManager(private val context: Context) {

    interface SocialLoginCallback {
        fun onSuccess(provider: String, userId: String, token: String)
        fun onError(provider: String, error: String)
        fun onCancel(provider: String)
    }

    private val facebookCallbackManager: CallbackManager = CallbackManager.Factory.create()
    private var googleSignInClient: GoogleSignInClient? = null
    private var callback: SocialLoginCallback? = null

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val securePrefs = EncryptedSharedPreferences.create(
        context,
        "social_login_config",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    init {
        initializeGoogleSignIn()
    }

    private fun getFacebookAppId(): String {
        return securePrefs.getString("facebook_app_id", null)
            ?: throw IllegalStateException("Facebook App ID not configured. Please set it using configureFacebook()")
    }

    private fun getFacebookAppSecret(): String {
        return securePrefs.getString("facebook_app_secret", null)
            ?: throw IllegalStateException("Facebook App Secret not configured. Please set it using configureFacebook()")
    }

    private fun getGoogleClientId(): String {
        return securePrefs.getString("google_client_id", null)
            ?: throw IllegalStateException("Google Client ID not configured. Please set it using configureGoogle()")
    }

    private fun getGoogleClientSecret(): String {
        return securePrefs.getString("google_client_secret", null)
            ?: throw IllegalStateException("Google Client Secret not configured. Please set it using configureGoogle()")
    }

    fun configureFacebook(appId: String, appSecret: String) {
        securePrefs.edit().apply {
            putString("facebook_app_id", appId)
            putString("facebook_app_secret", appSecret)
            apply()
        }
    }

    fun configureGoogle(clientId: String, clientSecret: String) {
        securePrefs.edit().apply {
            putString("google_client_id", clientId)
            putString("google_client_secret", clientSecret)
            apply()
        }
        initializeGoogleSignIn()
    }

    private fun initializeGoogleSignIn() {
        try {
            val clientId = getGoogleClientId()
            val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
                .requestIdToken(clientId)
                .requestEmail()
                .build()
            googleSignInClient = GoogleSignIn.getClient(context, gso)
        } catch (e: IllegalStateException) {
            // Google not configured yet
        }
    }

    fun loginWithFacebook(activity: Activity, callback: SocialLoginCallback) {
        this.callback = callback
        
        LoginManager.getInstance().registerCallback(facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val userId = result.accessToken.userId
                    val token = result.accessToken.token
                    callback.onSuccess("Facebook", userId, token)
                }

                override fun onCancel() {
                    callback.onCancel("Facebook")
                }

                override fun onError(error: FacebookException) {
                    callback.onError("Facebook", error.message ?: "Unknown error")
                }
            })

        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            listOf("email", "public_profile")
        )
    }

    fun loginWithGoogle(activity: Activity, launcher: ActivityResultLauncher<Intent>) {
        googleSignInClient?.let {
            val signInIntent = it.signInIntent
            launcher.launch(signInIntent)
        } ?: run {
            callback?.onError("Google", "Google Sign-In not configured")
        }
    }

    fun handleGoogleSignInResult(task: Task<GoogleSignInAccount>, callback: SocialLoginCallback) {
        try {
            val account = task.getResult(ApiException::class.java)
            val userId = account?.id ?: ""
            val token = account?.idToken ?: ""
            callback.onSuccess("Google", userId, token)
        } catch (e: ApiException) {
            callback.onError("Google", "Sign in failed: ${e.statusCode}")
        }
    }

    fun handleFacebookActivityResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        return facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    fun logout() {
        LoginManager.getInstance().logOut()
        googleSignInClient?.signOut()
    }
}

// SocialLoginActivity.kt
package com.example.sociallogin

import android.content.Intent
import android.os.Bundle
import android.widget.Button
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import com.google.android.gms.auth.api.signin.GoogleSignIn

class SocialLoginActivity : AppCompatActivity() {

    private lateinit var socialLoginManager: SocialLoginManager

    private val googleSignInLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        val task = GoogleSignIn.getSignedInAccountFromIntent(result.data)
        socialLoginManager.handleGoogleSignInResult(task, loginCallback)
    }

    private val loginCallback = object : SocialLoginManager.SocialLoginCallback {
        override fun onSuccess(provider: String, userId: String, token: String) {
            Toast.makeText(
                this@SocialLoginActivity,
                "$provider login successful! User: $userId",
                Toast.LENGTH_LONG
            ).show()
        }

        override fun onError(provider: String, error: String) {
            Toast.makeText(
                this@SocialLoginActivity,
                "$provider login failed: $error",
                Toast.LENGTH_LONG
            ).show()
        }

        override fun onCancel(provider: String) {
            Toast.makeText(
                this@SocialLoginActivity,
                "$provider login cancelled",
                Toast.LENGTH_SHORT
            ).show()
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_social_login)

        socialLoginManager = SocialLoginManager(this)
        
        // Configure credentials from secure source (environment variables, remote config, etc.)
        // These should be loaded from a secure backend or build configuration
        val facebookAppId = BuildConfig.FACEBOOK_APP_ID
        val facebookAppSecret = BuildConfig.FACEBOOK_APP_SECRET
        val googleClientId = BuildConfig.GOOGLE_CLIENT_ID
        val googleClientSecret = BuildConfig.GOOGLE_CLIENT_SECRET
        
        socialLoginManager.configureFacebook(facebookAppId, facebookAppSecret)
        socialLoginManager.configureGoogle(googleClientId, googleClientSecret)

        findViewById<Button>(R.id.btnFacebookLogin).setOnClickListener {
            socialLoginManager.loginWithFacebook(this, loginCallback)
        }

        findViewById<Button>(R.id.btnGoogleLogin).setOnClickListener {
            socialLoginManager.loginWithGoogle(this, googleSignInLauncher)
        }

        findViewById<Button>(R.id.btnLogout).setOnClickListener {
            socialLoginManager.logout()
            Toast.makeText(this, "Logged out", Toast.LENGTH_SHORT).show()
        }
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginManager.handleFacebookActivityResult(requestCode, resultCode, data)
    }
}

